sys_ui_page.processing_script:
(function() {

    if (request.getParameter("airop_action") != "run_now") return;

    // Check if another assessment is already running
    var running = new GlideRecord("x_snc_airop_assessment_run");
    running.addQuery("status", "running");
    running.setLimit(1);
    running.query();
    if (running.next()) {
        gs.addErrorMessage("An assessment is already running: " +
            running.getValue("name") +
            ". Only one assessment can run at a time. Please wait for it to complete.");
        response.sendRedirect("ui_page.do?sys_id=25c534f7cf68cf908935fb251d851c07");
        return;
    }

    // Check at least one module is enabled
    var propMap = {
        "ITSM":            "x_snc_airop.run_itsm",
        "ITOM":            "x_snc_airop.run_itom",
        "CMDB":            "x_snc_airop.run_cmdb",
        "HRSD":            "x_snc_airop.run_hrsd",
        "CSM":             "x_snc_airop.run_csm",
        "FIELD_SERVICE":   "x_snc_airop.run_field_service",
        "AIOPS":           "x_snc_airop.module.AIOPS.enabled",
        "GRC":             "x_snc_airop.run_grc",
        "SPM":             "x_snc_airop.run_spm",
        "PLATFORM":        "x_snc_airop.run_platform",
        "VIRTUAL_AGENT":   "x_snc_airop.run_virtual_agent",
        "DEX":             "x_snc_airop.module.DEX.enabled",
        "SECOPS":          "x_snc_airop.module.SECOPS.enabled",
        "HS":          "x_snc_airop.module.HS.enabled",
        "OTSM":          "x_snc_airop.module.OTSM.enabled",
        "CREATOR":          "x_snc_airop.module.CREATOR.enabled",
        "SPO":          "x_snc_airop.module.SPO.enabled",
        "TPRM":          "x_snc_airop.module.TPRM.enabled",
        "LSD":          "x_snc_airop.module.LSD.enabled",
        "WSD":          "x_snc_airop.module.WSD.enabled",
        "HAM":          "x_snc_airop.module.HAM.enabled",
        "SAM":          "x_snc_airop.module.SAM.enabled",
        "DEX":             "x_snc_airop.module.DEX.enabled",
        "SECOPS":          "x_snc_airop.module.SECOPS.enabled"
    };
    var enabled = [];
    for (var m in propMap) {
        if (gs.getProperty(propMap[m], "false") === "true") enabled.push(m);
    }
    if (enabled.length === 0) {
        gs.addErrorMessage("No modules are currently enabled. Please enable at least one module in Configuration before running an assessment.");
        response.sendRedirect("ui_page.do?sys_id=25c534f7cf68cf908935fb251d851c07");
        return;
    }

    // Create the run record with status = running
    var runGr = new GlideRecord("x_snc_airop_assessment_run");
    runGr.setValue("name",            "AI Readiness Checks for: " + enabled.join(", "));
    runGr.setValue("run_date",        new GlideDateTime());
    runGr.setValue("triggered_by",    gs.getUserID());
    runGr.setValue("status",          "running");
    runGr.setValue("environment_type","unknown");
    runGr.setValue("modules_scanned", enabled.join(", "));
    var runId = runGr.insert();

    // Fire the scheduled job immediately
    var job = new GlideRecord("sysauto_script");
    job.addQuery("name", "AIROP Scheduled Assessment");
    job.setLimit(1);
    job.query();
    if (job.next()) {
        job.setValue("next_action", new GlideDateTime());
        job.setValue("active",      true);
        job.update();
    }

    // Redirect to the new run record
    response.sendRedirect("x_snc_airop_assessment_run.do?sys_id=" + runId);

})();
